def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        if ratio < 0.3:
            for k in range(1, 6):
                score += ((0.3 - ratio) ** k) * (k*2)
            if capacity % 2 == 0:
                score -= 1.5
            else:
                score += 0.7
        elif 0.3 <= ratio < 0.7:
            multiplier = 1
            for n in range(3):
                if n % 2 == 0:
                    multiplier *= (ratio + n)
                else:
                    multiplier /= (ratio + n)
            score = np.log1p(multiplier) * 10
            if int(capacity) % 5 == 0:
                score /= 2
            else:
                score *= 1.3
        elif 0.7 <= ratio <= 1:
            diff = 1 - ratio
            for power in range(1, 4):
                score += (diff ** power) * 20 / power
            if item > 0.5 * capacity:
                score += 5
            if capacity - item > 2:
                score -= 3
        else:
            overflow = ratio - 1
            penalty = 0
            for p in range(1, 5):
                penalty += overflow ** p * (5 - p)
            score = penalty * 15
            if capacity < item * 2:
                score += 10
            if int(capacity) % 3 == 0:
                score += 2
        if score < 0:
            score = abs(score) * 0.5
        priorities[i] = score
    max_val = np.nanmax(priorities[np.isfinite(priorities)])
    priorities[np.isinf(priorities)] = max_val + 50
    return priorities
